import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const x=JSON.parse('{"title":"Git-псевдонимы | Dotfiles (RU)","titleTemplate":":title","description":"Git-псевдонимы оболочки. Более 80 ярлыков для ускорения работы с коммитами, ветками, diff и удалёнными репозиториями.","frontmatter":{"title":"Git-псевдонимы | Dotfiles","description":"Git-псевдонимы оболочки. Более 80 ярлыков для ускорения работы с коммитами, ветками, diff и удалёнными репозиториями.","lang":"ru-RU","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Git-псевдонимы preview","canonical":"/ru/aliases/git/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Git-псевдонимы","pageType":"docs","schemaType":"WebPage","metaTitle":"Git-псевдонимы - Dotfiles (RU)","permalink":"/ru/aliases/git/","sidebar":true,"meta":[{"name":"keywords","content":"git aliases, git shortcuts, git dotfiles, git commit, git branch, shell, bash, zsh"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Git-псевдонимы оболочки. Более 80 ярлыков для ускорения работы с коммитами, ветками, diff и удалёнными репозиториями."},{"name":"twitter:title","content":"Git-псевдонимы - Dotfiles"},{"name":"og:title","content":"Git-псевдонимы - Dotfiles"},{"name":"og:description","content":"Git-псевдонимы оболочки. Более 80 ярлыков для ускорения работы с коммитами, ветками, diff и удалёнными репозиториями."},{"name":"og:image:alt","content":"Dotfiles - Простой дизайн для вашей жизни в командной оболочке"},{"name":"og:locale","content":"ru_RU"}]},"headers":[],"relativePath":"ru/aliases/git/index.md","filePath":"ru/aliases/git/index.md","lastUpdated":1773010926000}'),i={name:"ru/aliases/git/index.md"};function o(g,t,s,c,n,r){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="git-псевдонимы" tabindex="-1">Git-псевдонимы <a class="header-anchor" href="#git-псевдонимы" aria-label="Permalink to &quot;Git-псевдонимы&quot;">​</a></h1><p>Оптимизируйте рабочий процесс контроля версий с помощью мощных ярлыков.</p><h2 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h2><p>Git-псевдонимы создают ярлыки для часто используемых команд Git. Являясь частью конфигурации <a href="https://github.com/sebastienrousseau/dotfiles" target="_blank" rel="noreferrer">Dotfiles</a>, эти псевдонимы автоматически загружаются через Chezmoi.</p><p>Определённые в <code>git.aliases.sh</code> и <code>signing.aliases.sh</code>, псевдонимы доступны в любой сессии Bash или Zsh после установки.</p><h2 id="справочник" tabindex="-1">Справочник <a class="header-anchor" href="#справочник" aria-label="Permalink to &quot;Справочник&quot;">​</a></h2><h3 id="ядро" tabindex="-1">Ядро <a class="header-anchor" href="#ядро" aria-label="Permalink to &quot;Ядро&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>g</code></td><td style="text-align:left;"><code>git</code></td><td style="text-align:left;">Сокращение для git</td></tr><tr><td style="text-align:left;"><code>gtp</code></td><td style="text-align:left;"><code>git rev-parse --show-toplevel</code></td><td style="text-align:left;">Показать корневую директорию репозитория</td></tr><tr><td style="text-align:left;"><code>grpa</code></td><td style="text-align:left;"><code>git rev-parse --abbrev-ref HEAD</code></td><td style="text-align:left;">Показать имя текущей ветки</td></tr><tr><td style="text-align:left;"><code>gconfl</code></td><td style="text-align:left;"><code>git config --list</code></td><td style="text-align:left;">Показать все настройки Git</td></tr><tr><td style="text-align:left;"><code>gconfr</code></td><td style="text-align:left;"><code>git config --local --get remote.origin.url</code></td><td style="text-align:left;">Показать URL удалённого origin</td></tr><tr><td style="text-align:left;"><code>gconfdiff</code></td><td style="text-align:left;"><code>git config alias.dcolor &quot;diff --color-words&quot;</code></td><td style="text-align:left;">Настроить псевдоним цветного diff</td></tr></tbody></table><h3 id="рабочая-область" tabindex="-1">Рабочая область <a class="header-anchor" href="#рабочая-область" aria-label="Permalink to &quot;Рабочая область&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ga</code></td><td style="text-align:left;"><code>git add</code></td><td style="text-align:left;">Добавить файлы в индекс</td></tr><tr><td style="text-align:left;"><code>gaa</code></td><td style="text-align:left;"><code>git add --all</code></td><td style="text-align:left;">Добавить все изменения в индекс</td></tr><tr><td style="text-align:left;"><code>gad</code></td><td style="text-align:left;"><code>git add .</code></td><td style="text-align:left;">Добавить текущую директорию в индекс</td></tr><tr><td style="text-align:left;"><code>gau</code></td><td style="text-align:left;"><code>git add --update</code></td><td style="text-align:left;">Добавить изменения и удаления в индекс</td></tr><tr><td style="text-align:left;"><code>gcl</code></td><td style="text-align:left;"><code>git clone</code></td><td style="text-align:left;">Клонировать репозиторий</td></tr><tr><td style="text-align:left;"><code>gin</code></td><td style="text-align:left;"><code>git init</code></td><td style="text-align:left;">Инициализировать новый Git-репозиторий</td></tr><tr><td style="text-align:left;"><code>gco</code></td><td style="text-align:left;"><code>git checkout</code></td><td style="text-align:left;">Переключить ветки</td></tr><tr><td style="text-align:left;"><code>gcb</code></td><td style="text-align:left;"><code>git checkout -b</code></td><td style="text-align:left;">Создать и переключиться на новую ветку</td></tr><tr><td style="text-align:left;"><code>gdis</code></td><td style="text-align:left;"><code>git checkout --</code></td><td style="text-align:left;">Отменить изменения в рабочей директории</td></tr><tr><td style="text-align:left;"><code>grs</code></td><td style="text-align:left;"><code>git restore</code></td><td style="text-align:left;">Восстановить файлы рабочего дерева</td></tr><tr><td style="text-align:left;"><code>gmv</code></td><td style="text-align:left;"><code>git mv</code></td><td style="text-align:left;">Переместить или переименовать файл</td></tr><tr><td style="text-align:left;"><code>grm</code></td><td style="text-align:left;"><code>git rm</code></td><td style="text-align:left;">Удалить файлы</td></tr><tr><td style="text-align:left;"><code>grmc</code></td><td style="text-align:left;"><code>git rm --cached</code></td><td style="text-align:left;">Убрать файл из индекса</td></tr><tr><td style="text-align:left;"><code>gst</code></td><td style="text-align:left;"><code>git status</code></td><td style="text-align:left;">Показать состояние рабочего дерева</td></tr><tr><td style="text-align:left;"><code>gsts</code></td><td style="text-align:left;"><code>git status --short</code></td><td style="text-align:left;">Показать состояние в кратком формате</td></tr><tr><td style="text-align:left;"><code>gstsb</code></td><td style="text-align:left;"><code>git status --short --branch</code></td><td style="text-align:left;">Краткое состояние с информацией о ветке</td></tr><tr><td style="text-align:left;"><code>gsta</code></td><td style="text-align:left;"><code>git stash save</code></td><td style="text-align:left;">Сохранить текущие изменения в stash</td></tr><tr><td style="text-align:left;"><code>gstp</code></td><td style="text-align:left;"><code>git stash pop</code></td><td style="text-align:left;">Применить последний stash</td></tr><tr><td style="text-align:left;"><code>gstd</code></td><td style="text-align:left;"><code>git stash drop</code></td><td style="text-align:left;">Удалить последний stash</td></tr><tr><td style="text-align:left;"><code>gclout</code></td><td style="text-align:left;"><code>git clean -df &amp;&amp; git checkout -- .</code></td><td style="text-align:left;">Отменить все изменения</td></tr></tbody></table><h3 id="коммиты" tabindex="-1">Коммиты <a class="header-anchor" href="#коммиты" aria-label="Permalink to &quot;Коммиты&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gc</code></td><td style="text-align:left;"><code>git commit -a</code></td><td style="text-align:left;">Закоммитить отслеживаемые изменения</td></tr><tr><td style="text-align:left;"><code>gca</code></td><td style="text-align:left;"><code>git commit --amend</code></td><td style="text-align:left;">Изменить последний коммит</td></tr><tr><td style="text-align:left;"><code>gcall</code></td><td style="text-align:left;"><code>git add -A &amp;&amp; git commit -av</code></td><td style="text-align:left;">Добавить всё и закоммитить</td></tr><tr><td style="text-align:left;"><code>gcam</code></td><td style="text-align:left;"><code>git commit --amend --message</code></td><td style="text-align:left;">Изменить коммит с новым сообщением</td></tr><tr><td style="text-align:left;"><code>gcane</code></td><td style="text-align:left;"><code>git commit --amend --no-edit</code></td><td style="text-align:left;">Изменить без изменения сообщения</td></tr><tr><td style="text-align:left;"><code>gcm</code></td><td style="text-align:left;"><code>git commit --message</code></td><td style="text-align:left;">Коммит с инлайн-сообщением</td></tr></tbody></table><h3 id="diff-и-история" tabindex="-1">Diff и история <a class="header-anchor" href="#diff-и-история" aria-label="Permalink to &quot;Diff и история&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gd</code></td><td style="text-align:left;"><code>git diff</code></td><td style="text-align:left;">Показать неиндексированные изменения</td></tr><tr><td style="text-align:left;"><code>gdch</code></td><td style="text-align:left;"><code>git diff --name-status</code></td><td style="text-align:left;">Показать имена изменённых файлов</td></tr><tr><td style="text-align:left;"><code>gdh</code></td><td style="text-align:left;"><code>git diff HEAD</code></td><td style="text-align:left;">Показать изменения с последнего коммита</td></tr><tr><td style="text-align:left;"><code>gdstaged</code></td><td style="text-align:left;"><code>git diff --staged</code></td><td style="text-align:left;">Показать индексированные изменения</td></tr><tr><td style="text-align:left;"><code>gdcached</code></td><td style="text-align:left;"><code>git diff --cached</code></td><td style="text-align:left;">Показать изменения между индексом и HEAD</td></tr><tr><td style="text-align:left;"><code>gdstat</code></td><td style="text-align:left;"><code>git diff --stat --ignore-space-change -r</code></td><td style="text-align:left;">Сгенерировать diffstat</td></tr><tr><td style="text-align:left;"><code>gl</code></td><td style="text-align:left;"><code>git log --since=&quot;last month&quot; --oneline</code></td><td style="text-align:left;">Однострочный лог за месяц</td></tr><tr><td style="text-align:left;"><code>glg</code></td><td style="text-align:left;"><code>git log --graph --all --oneline --decorate</code></td><td style="text-align:left;">Графический лог всех веток</td></tr><tr><td style="text-align:left;"><code>glgg</code></td><td style="text-align:left;"><code>git log --oneline --graph --full-history --all --color --decorate</code></td><td style="text-align:left;">Полный графический лог</td></tr><tr><td style="text-align:left;"><code>glc</code></td><td style="text-align:left;"><code>git log --oneline --reverse</code></td><td style="text-align:left;">Хронологический однострочный лог</td></tr><tr><td style="text-align:left;"><code>gld</code></td><td style="text-align:left;"><code>git log --since=1-day-ago</code></td><td style="text-align:left;">Лог за последние 24 часа</td></tr></tbody></table><h3 id="ветки" tabindex="-1">Ветки <a class="header-anchor" href="#ветки" aria-label="Permalink to &quot;Ветки&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gb</code></td><td style="text-align:left;"><code>git branch</code></td><td style="text-align:left;">Показать локальные ветки</td></tr><tr><td style="text-align:left;"><code>gbd</code></td><td style="text-align:left;"><code>git branch -d</code></td><td style="text-align:left;">Удалить слитую ветку</td></tr><tr><td style="text-align:left;"><code>gbl</code></td><td style="text-align:left;"><code>git branch -l</code></td><td style="text-align:left;">Показать ветки по шаблону</td></tr><tr><td style="text-align:left;"><code>gbr</code></td><td style="text-align:left;"><code>git branch -r</code></td><td style="text-align:left;">Показать удалённые ветки</td></tr><tr><td style="text-align:left;"><code>gbrd</code></td><td style="text-align:left;"><code>git branch -d -r</code></td><td style="text-align:left;">Удалить удалённую отслеживающую ветку</td></tr><tr><td style="text-align:left;"><code>gswb</code></td><td style="text-align:left;"><code>git switch</code></td><td style="text-align:left;">Переключить ветки (современный)</td></tr></tbody></table><h3 id="удаленные-репозитории-и-push-pull" tabindex="-1">Удалённые репозитории и Push/Pull <a class="header-anchor" href="#удаленные-репозитории-и-push-pull" aria-label="Permalink to &quot;Удалённые репозитории и Push/Pull&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gf</code></td><td style="text-align:left;"><code>git fetch</code></td><td style="text-align:left;">Получить с удалённого репозитория</td></tr><tr><td style="text-align:left;"><code>gp</code></td><td style="text-align:left;"><code>git pull</code></td><td style="text-align:left;">Загрузить с удалённого репозитория</td></tr><tr><td style="text-align:left;"><code>gph</code></td><td style="text-align:left;"><code>git push</code></td><td style="text-align:left;">Отправить на удалённый репозиторий</td></tr><tr><td style="text-align:left;"><code>gpo</code></td><td style="text-align:left;"><code>git push origin</code></td><td style="text-align:left;">Отправить на origin</td></tr><tr><td style="text-align:left;"><code>gpb</code></td><td style="text-align:left;"><code>git push --set-upstream origin $(git branch --show-current)</code></td><td style="text-align:left;">Установить upstream и отправить</td></tr><tr><td style="text-align:left;"><code>gpoll</code></td><td style="text-align:left;"><code>git push origin --all</code></td><td style="text-align:left;">Отправить все ветки на origin</td></tr><tr><td style="text-align:left;"><code>gr</code></td><td style="text-align:left;"><code>git remote</code></td><td style="text-align:left;">Управление удалёнными репозиториями</td></tr><tr><td style="text-align:left;"><code>gra</code></td><td style="text-align:left;"><code>git remote add</code></td><td style="text-align:left;">Добавить новый удалённый репозиторий</td></tr><tr><td style="text-align:left;"><code>grao</code></td><td style="text-align:left;"><code>git remote add origin</code></td><td style="text-align:left;">Добавить origin</td></tr><tr><td style="text-align:left;"><code>grv</code></td><td style="text-align:left;"><code>git remote -v</code></td><td style="text-align:left;">Показать URL удалённых репозиториев</td></tr></tbody></table><h3 id="отмена-и-сброс" tabindex="-1">Отмена и сброс <a class="header-anchor" href="#отмена-и-сброс" aria-label="Permalink to &quot;Отмена и сброс&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>grev</code></td><td style="text-align:left;"><code>git revert</code></td><td style="text-align:left;">Отменить коммит</td></tr><tr><td style="text-align:left;"><code>grevnc</code></td><td style="text-align:left;"><code>git revert --no-commit</code></td><td style="text-align:left;">Отменить без автокоммита</td></tr><tr><td style="text-align:left;"><code>grb</code></td><td style="text-align:left;"><code>git rebase</code></td><td style="text-align:left;">Перебазировать текущую ветку</td></tr><tr><td style="text-align:left;"><code>grbk</code></td><td style="text-align:left;"><code>git reset --soft HEAD^</code></td><td style="text-align:left;">Отменить последний коммит</td></tr><tr><td style="text-align:left;"><code>grescl</code></td><td style="text-align:left;"><code>git reset --hard HEAD~1 &amp;&amp; git clean -fd</code></td><td style="text-align:left;">Жёсткий сброс и очистка</td></tr><tr><td style="text-align:left;"><code>gresh</code></td><td style="text-align:left;"><code>git reset --hard HEAD~1</code></td><td style="text-align:left;">Жёсткий сброс к предыдущему коммиту</td></tr><tr><td style="text-align:left;"><code>gresp</code></td><td style="text-align:left;"><code>git reset --hard &amp;&amp; git clean -ffdx</code></td><td style="text-align:left;">Сброс в исходное состояние</td></tr><tr><td style="text-align:left;"><code>gress</code></td><td style="text-align:left;"><code>git reset --soft HEAD~1</code></td><td style="text-align:left;">Мягкий сброс</td></tr></tbody></table><h3 id="субмодули" tabindex="-1">Субмодули <a class="header-anchor" href="#субмодули" aria-label="Permalink to &quot;Субмодули&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gsm</code></td><td style="text-align:left;"><code>git submodule</code></td><td style="text-align:left;">Управление субмодулями</td></tr><tr><td style="text-align:left;"><code>gsmi</code></td><td style="text-align:left;"><code>git submodule init</code></td><td style="text-align:left;">Инициализировать субмодули</td></tr><tr><td style="text-align:left;"><code>gsma</code></td><td style="text-align:left;"><code>git submodule add</code></td><td style="text-align:left;">Добавить субмодуль</td></tr><tr><td style="text-align:left;"><code>gsms</code></td><td style="text-align:left;"><code>git submodule sync</code></td><td style="text-align:left;">Синхронизировать URL субмодулей</td></tr><tr><td style="text-align:left;"><code>gsmu</code></td><td style="text-align:left;"><code>git submodule update</code></td><td style="text-align:left;">Обновить субмодули</td></tr><tr><td style="text-align:left;"><code>gsmui</code></td><td style="text-align:left;"><code>git submodule update --init</code></td><td style="text-align:left;">Обновить и инициализировать</td></tr><tr><td style="text-align:left;"><code>gsmuir</code></td><td style="text-align:left;"><code>git submodule update --init --recursive</code></td><td style="text-align:left;">Обновить, инициализировать, рекурсивно</td></tr></tbody></table><h3 id="инструменты" tabindex="-1">Инструменты <a class="header-anchor" href="#инструменты" aria-label="Permalink to &quot;Инструменты&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gg</code></td><td style="text-align:left;"><code>git grep</code></td><td style="text-align:left;">Поиск по содержимому репозитория</td></tr><tr><td style="text-align:left;"><code>gbs</code></td><td style="text-align:left;"><code>git bisect</code></td><td style="text-align:left;">Бинарный поиск коммита с ошибкой</td></tr><tr><td style="text-align:left;"><code>undopush</code></td><td style="text-align:left;"><code>git push -f origin HEAD^:master</code></td><td style="text-align:left;">Принудительно отменить последний push</td></tr></tbody></table><h3 id="подписание-и-безопасность" tabindex="-1">Подписание и безопасность <a class="header-anchor" href="#подписание-и-безопасность" aria-label="Permalink to &quot;Подписание и безопасность&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Псевдоним</th><th style="text-align:left;">Команда</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><code>enable-signing</code></td><td style="text-align:left;"><em>(интерактивный мастер)</em></td><td style="text-align:left;">Настроить подписание коммитов GPG или SSH</td></tr><tr><td style="text-align:left;"><code>verify-signatures</code></td><td style="text-align:left;"><code>git log --show-signature -n 10</code></td><td style="text-align:left;">Проверить подписи последних 10 коммитов</td></tr><tr><td style="text-align:left;"><code>check-signing</code></td><td style="text-align:left;"><code>git config --list | grep &quot;gpg|signing&quot;</code></td><td style="text-align:left;">Проверить текущую конфигурацию подписания</td></tr></tbody></table>',26)])])}const y=e(i,[["render",o]]);export{x as __pageData,y as default};
